%%%%%%%%%% Function fScanDirLstV01.m %%%%%%%%%%% Function to get scan directory list, ver.1%% Kei Nakamura% Created on Monday, MJune 1st 2009.% Modified on%% function scn = fScanDirLstV01(mDir);% give number and list of directory to scan% against input scan% nmbImg: number of images to go through% imgLst: image list (shot number)% espcDir: directory to look at% nmbSht: number of shots from trex logfilefunction [nmbImg,imgLst] = fMspcDirLstV01(espcDir,nmbSht)   % function headerimgExst0 = fMspcShtLstV01(espcDir,nmbSht,0);    % get a list for cam0imgExst2 = fMspcShtLstV01(espcDir,nmbSht,2);    % get a list for cam2imgExst3 = fMspcShtLstV01(espcDir,nmbSht,3);    % get a list for cam3imgExst4 = fMspcShtLstV01(espcDir,nmbSht,4);    % get a list for cam4imgExst = imgExst0.*imgExst2.*imgExst3.*imgExst4;nmbImg = sum(imgExst);aaa = [1:nmbSht]';imgExst = imgExst.*aaa;imgLst = find(imgExst~=0);
